questionvariables.text:
/* Random radius and height */
R: rand(13)+8;     /* bottom radius 8–20 cm */
r: rand(7)+3;      /* top radius 3–9 cm */
h: rand(31)+10;    /* height 10–40 cm */

/* Ensure r < R */
if r >= R then r: R-1;

bracket_value:R^2 + R*r + r^2;
height_bracket_value: bracket_value *h;

/* Volume calculation */
V: (1/3)*%pi*h*(bracket_value);

/* Convert to litres */
V_litre: V/1000;

/* Teacher answer */
ta: V_litre;

/* Scaled dimensions for drawing */
Rdraw: R/4;
rdraw: r/4;
hdraw: h/4;
